// ============================================
// ANALIZADOR DE PATRONES - DETECTA COMPORTAMIENTOS
// ============================================

const events = $input.all();

// Contadores por intención
const intentCounts = {};
const territoryStats = {};
const productStats = {};

events.forEach(item => {
  const event = item.json;
  const intent = event.payload?.data?.intent || 'unknown';
  const territory = event.metadata?.territory || 'unknown';
  const product = event.payload?.data?.product || 'unknown';

  // Contar intenciones
  intentCounts[intent] = (intentCounts[intent] || 0) + 1;

  // Stats por territorio
  if (!territoryStats[territory]) {
    territoryStats[territory] = { total: 0, intents: {} };
  }
  territoryStats[territory].total++;
  territoryStats[territory].intents[intent] = (territoryStats[territory].intents[intent] || 0) + 1;

  // Stats por producto
  if (product !== 'unknown') {
    productStats[product] = (productStats[product] || 0) + 1;
  }
});

// Detectar patrones
const patterns = [];

// Patrón 1: Intención dominante
const maxIntent = Object.entries(intentCounts).sort((a, b) => b[1] - a[1])[0];
if (maxIntent && maxIntent[1] > 3) {
  patterns.push({
    type: 'intent_dominance',
    description: `Aumento en intención '${maxIntent[0]}' (${maxIntent[1]} eventos en 5 min)`,
    action: 'adjust_prompt_focus',
    priority: 'medium'
  });
}

// Patrón 2: Territorio caliente
const hotTerritory = Object.entries(territoryStats)
  .filter(([_, stats]) => stats.total > 5)
  .sort((a, b) => b[1].total - a[1].total)[0];

if (hotTerritory) {
  patterns.push({
    type: 'territory_hot',
    description: `Territorio ${hotTerritory[0]} muy activo (${hotTerritory[1].total} eventos)`,
    action: 'increase_local_resources',
    priority: 'high'
  });
}

// Patrón 3: Producto trending
const trendingProduct = Object.entries(productStats).sort((a, b) => b[1] - a[1])[0];
if (trendingProduct && trendingProduct[1] > 2) {
  patterns.push({
    type: 'product_trending',
    description: `Producto '${trendingProduct[0]}' en demanda (${trendingProduct[1]} menciones)`,
    action: 'update_stock_priority',
    priority: 'high'
  });
}

// Construir actualización del sistema
const systemUpdate = {
  timestamp: new Date().toISOString(),
  window: "last_5_minutes",
  total_events: events.length,
  patterns_detected: patterns,
  intent_distribution: intentCounts,
  territory_stats: territoryStats,
  product_stats: productStats,
  actions: {
    update_mcp_prompt: patterns.length > 0,
    notify_territories: Object.keys(territoryStats),
    adjust_pricing: trendingProduct ? [trendingProduct[0]] : []
  }
};

return { json: systemUpdate };
